const MAX_HISTORY = 2000;
const MIN_POINT_DISTANCE_M = 8;
const MAX_ACCURACY_M = 15;
const SIMPLIFY_TOLERANCE_M = 5;
const SIMPLIFY_EVERY_N_POINTS = 25;
const RECENT_POINT_WINDOW_MS = 5 * 60 * 1000;
const MIN_TIME_BETWEEN_POINTS_MS = 1000;
const MIN_MOVEMENT_SPEED_MPS = 0.3;
const ACCURACY_DISTANCE_MULTIPLIER = 1.2;
const MAX_REASONABLE_SPEED_MPS = 18;
const STATIONARY_SPEED_THRESHOLD_MPS = 0.5;
const STATIONARY_DRIFT_RADIUS_M = 12;
const STATIONARY_MAX_ACCURACY_M = 20;

function asNumber(value) {
    if (value === undefined || value === null || value === "") {
        return NaN;
    }
    return Number(value);
}

function distanceMeters(pointA, pointB) {
    if (!pointA || !pointB) return Number.POSITIVE_INFINITY;
    const earthRadiusMeters = 6371000;
    const toRadians = function (degreeValue) { return degreeValue * Math.PI / 180; };
    const latDelta = toRadians(pointB.lat - pointA.lat);
    const lonDelta = toRadians(pointB.lon - pointA.lon);
    const haversine = Math.sin(latDelta / 2) * Math.sin(latDelta / 2) +
        Math.cos(toRadians(pointA.lat)) * Math.cos(toRadians(pointB.lat)) *
        Math.sin(lonDelta / 2) * Math.sin(lonDelta / 2);
    return 2 * earthRadiusMeters * Math.atan2(Math.sqrt(haversine), Math.sqrt(1 - haversine));
}

function isValidCandidate(newPoint, previousPoint) {
    if (!newPoint || typeof newPoint.lat !== "number" || typeof newPoint.lon !== "number") {
        return false;
    }
    if (typeof newPoint.accuracy === "number" && newPoint.accuracy > MAX_ACCURACY_M) {
        return false;
    }
    if (!previousPoint) return true;

    const previousTimestamp = Number(previousPoint.timestamp) || 0;
    const currentTimestamp = Number(newPoint.timestamp) || Date.now();
    const timeSinceLastPoint = currentTimestamp - previousTimestamp;

    if (timeSinceLastPoint < MIN_TIME_BETWEEN_POINTS_MS) {
        return false;
    }

    const pointDistance = distanceMeters(previousPoint, newPoint);
    const elapsedSeconds = timeSinceLastPoint > 0 ? (timeSinceLastPoint / 1000) : 0;
    if (elapsedSeconds > 0) {
        const estimatedSpeedMetersPerSecond = pointDistance / elapsedSeconds;
        if (estimatedSpeedMetersPerSecond > MAX_REASONABLE_SPEED_MPS) {
            return false;
        }
    }
    const newAccuracy = typeof newPoint.accuracy === "number" ? newPoint.accuracy : 0;
    const previousAccuracy = typeof previousPoint.accuracy === "number" ? previousPoint.accuracy : 0;
    const noiseRadius = Math.max(newAccuracy, previousAccuracy) * ACCURACY_DISTANCE_MULTIPLIER;
    const effectiveMinDistance = Math.max(MIN_POINT_DISTANCE_M, noiseRadius);

    if (pointDistance < effectiveMinDistance) {
        return timeSinceLastPoint > RECENT_POINT_WINDOW_MS;
    }

    if (typeof newPoint.speed === "number" && newPoint.speed >= 0 && newPoint.speed < MIN_MOVEMENT_SPEED_MPS) {
        return timeSinceLastPoint > RECENT_POINT_WINDOW_MS;
    }

    return true;
}

function perpendicularDistanceMeters(point, lineStart, lineEnd) {
    const latitudeToMeters = 111320;
    const averageLatitudeRadians = (lineStart.lat + lineEnd.lat) * Math.PI / 360;
    const longitudeToMeters = 111320 * Math.cos(averageLatitudeRadians);
    const startX = lineStart.lon * longitudeToMeters;
    const startY = lineStart.lat * latitudeToMeters;
    const endX = lineEnd.lon * longitudeToMeters;
    const endY = lineEnd.lat * latitudeToMeters;
    const pointX = point.lon * longitudeToMeters;
    const pointY = point.lat * latitudeToMeters;
    const segmentDx = endX - startX;
    const segmentDy = endY - startY;
    const segmentLengthSquared = segmentDx * segmentDx + segmentDy * segmentDy;
    if (segmentLengthSquared === 0) {
        const dx = pointX - startX;
        const dy = pointY - startY;
        return Math.sqrt(dx * dx + dy * dy);
    }
    const numerator = Math.abs(segmentDy * pointX - segmentDx * pointY + endX * startY - endY * startX);
    return numerator / Math.sqrt(segmentLengthSquared);
}

function simplifyPath(points, toleranceMeters) {
    if (!Array.isArray(points) || points.length < 3) {
        return Array.isArray(points) ? points.slice() : [];
    }
    const keepPointFlags = new Array(points.length).fill(false);
    keepPointFlags[0] = true;
    keepPointFlags[points.length - 1] = true;
    const segmentStack = [[0, points.length - 1]];
    while (segmentStack.length > 0) {
        const [startIndex, endIndex] = segmentStack.pop();
        let maxDistance = 0;
        let maxDistanceIndex = -1;
        for (let pointIndex = startIndex + 1; pointIndex < endIndex; pointIndex += 1) {
            const perpendicular = perpendicularDistanceMeters(points[pointIndex], points[startIndex], points[endIndex]);
            if (perpendicular > maxDistance) {
                maxDistance = perpendicular;
                maxDistanceIndex = pointIndex;
            }
        }
        if (maxDistance > toleranceMeters && maxDistanceIndex !== -1) {
            keepPointFlags[maxDistanceIndex] = true;
            segmentStack.push([startIndex, maxDistanceIndex]);
            segmentStack.push([maxDistanceIndex, endIndex]);
        }
    }
    const simplifiedPoints = [];
    for (let pointIndex = 0; pointIndex < points.length; pointIndex += 1) {
        if (keepPointFlags[pointIndex]) simplifiedPoints.push(points[pointIndex]);
    }
    return simplifiedPoints;
}

function appendToHistory(history, position) {
    const lastPoint = history.length > 0 ? history[history.length - 1] : null;
    if (!isValidCandidate(position, lastPoint)) {
        return { history: history, added: false };
    }
    history.push(position);
    if (history.length % SIMPLIFY_EVERY_N_POINTS === 0) {
        history = simplifyPath(history, SIMPLIFY_TOLERANCE_M);
    }
    if (history.length > MAX_HISTORY) {
        history = history.slice(-MAX_HISTORY);
    }
    return { history: history, added: true };
}

function stabilizePositionForStationaryDevice(nextPosition, previousPosition) {
    if (!nextPosition || !previousPosition) {
        return nextPosition;
    }
    const hasNextCoordinates = typeof nextPosition.lat === "number" && typeof nextPosition.lon === "number";
    const hasPreviousCoordinates = typeof previousPosition.lat === "number" && typeof previousPosition.lon === "number";
    if (!hasNextCoordinates || !hasPreviousCoordinates) {
        return nextPosition;
    }

    const pointDistance = distanceMeters(previousPosition, nextPosition);
    const speedValue = typeof nextPosition.speed === "number" && nextPosition.speed >= 0 ? nextPosition.speed : null;
    const accuracyValue = typeof nextPosition.accuracy === "number" && nextPosition.accuracy >= 0 ? nextPosition.accuracy : null;
    const isSlowOrStanding = speedValue !== null
        ? speedValue <= STATIONARY_SPEED_THRESHOLD_MPS
        : pointDistance <= STATIONARY_DRIFT_RADIUS_M;
    const accuracyIsGoodEnough = accuracyValue === null || accuracyValue <= STATIONARY_MAX_ACCURACY_M;
    const driftRadius = Math.max(
        STATIONARY_DRIFT_RADIUS_M,
        (accuracyValue !== null ? accuracyValue : 0) * ACCURACY_DISTANCE_MULTIPLIER
    );
    const shouldFreezeMarkerPosition = isSlowOrStanding && accuracyIsGoodEnough && pointDistance <= driftRadius;

    if (!shouldFreezeMarkerPosition) {
        return nextPosition;
    }

    return {
        user: nextPosition.user,
        device: nextPosition.device,
        key: nextPosition.key,
        owntracksTid: nextPosition.owntracksTid || null,
        lat: previousPosition.lat,
        lon: previousPosition.lon,
        accuracy: nextPosition.accuracy,
        speed: nextPosition.speed,
        heading: nextPosition.heading,
        battery: nextPosition.battery,
        timestamp: nextPosition.timestamp,
        receivedAt: nextPosition.receivedAt
    };
}

function trackingStateHasMissionAnchor(ts) {
    if (!ts || typeof ts !== "object") return false;
    const m = ts.missionStartPosition;
    return !!(m && typeof m.lat === "number" && typeof m.lon === "number" &&
        Number.isFinite(m.lat) && Number.isFinite(m.lon));
}

function cloneTrackingStateForKeyMerge(ts) {
    if (!ts || typeof ts !== "object") return null;
    function pos(p) {
        if (!p || typeof p !== "object") return null;
        if (typeof p.lat !== "number" || typeof p.lon !== "number") return null;
        if (!Number.isFinite(p.lat) || !Number.isFinite(p.lon)) return null;
        return { lat: p.lat, lon: p.lon, timestamp: p.timestamp != null ? p.timestamp : null };
    }
    const m = pos(ts.missionStartPosition);
    if (!m) return null;
    const r = pos(ts.returnPosition);
    const ret = r || { lat: m.lat, lon: m.lon, timestamp: m.timestamp };
    return {
        active: !!ts.active,
        trackingSessionId: ts.trackingSessionId != null ? ts.trackingSessionId : null,
        missionStartPosition: m,
        returnPosition: ret
    };
}

function coordinatesLookValidForBoat(p) {
    if (!p || typeof p !== "object") return false;
    if (p.lat === null || p.lon === null) return false;
    if (typeof p.lat !== "number" || typeof p.lon !== "number") return false;
    if (!Number.isFinite(p.lat) || !Number.isFinite(p.lon)) return false;
    if (Math.abs(p.lat) < 1e-7 && Math.abs(p.lon) < 1e-7) return false;
    if (Math.abs(p.lat) > 90 || Math.abs(p.lon) > 180) return false;
    return true;
}

function snapshotLastGoodForDevice(p, deviceKey) {
    return {
        user: p.user,
        device: p.device,
        key: deviceKey,
        owntracksTid: p.owntracksTid || null,
        lat: p.lat,
        lon: p.lon,
        accuracy: p.accuracy,
        speed: p.speed,
        heading: p.heading,
        battery: p.battery,
        timestamp: p.timestamp,
        receivedAt: p.receivedAt
    };
}

let raw = msg.payload;
if (Buffer.isBuffer(raw)) raw = raw.toString("utf8");

let p;
if (typeof raw === "string") {
    try {
        p = JSON.parse(raw);
    } catch (err) {
        node.warn("Tracking-logik: ungültiges JSON");
        return null;
    }
} else if (raw && typeof raw === "object") {
    p = raw;
} else {
    return null;
}

const topicParts = (msg.topic || "").split("/").filter(function (segment) {
    return segment.length > 0;
});

let username = "";
let deviceId = "";
if (topicParts.length >= 3) {
    username = topicParts[1];
    deviceId = topicParts[2];
} else if (topicParts.length === 2) {
    username = topicParts[0];
    deviceId = topicParts[1];
}

let lat = NaN;
let lon = NaN;
let accuracy = null;
let speed = null;
let heading = null;
let battery = null;
let timestamp = Date.now();
const receivedAt = Date.now();
const isOwntracks = p._type === "location";

if (isOwntracks) {
    lat = asNumber(p.lat);
    lon = asNumber(p.lon);
    accuracy = p.acc !== undefined ? asNumber(p.acc) : null;
    speed = p.vel !== undefined ? asNumber(p.vel) : null;
    heading = p.cog !== undefined ? asNumber(p.cog) : null;
    battery = p.batt !== undefined ? asNumber(p.batt) : null;
    timestamp = p.tst ? asNumber(p.tst) * 1000 : Date.now();
    if (p.tid && typeof p.tid === "string") {
        deviceId = deviceId || p.tid;
    }
    if (!username && typeof p.topic === "string") {
        const sub = p.topic.split("/");
        if (sub.length >= 2) {
            username = sub[0];
            deviceId = deviceId || sub[1];
        }
    }
} else {
    const coords = p.coords && typeof p.coords === "object" ? p.coords : null;
    lat = asNumber(p.lat != null ? p.lat : p.latitude);
    lon = asNumber(p.lon != null ? p.lon : p.longitude);
    if (coords && (isNaN(lat) || isNaN(lon))) {
        lat = asNumber(coords.lat != null ? coords.lat : coords.latitude);
        lon = asNumber(coords.lon != null ? coords.lon : (coords.longitude != null ? coords.longitude : coords.lng));
    }
    username = username || (typeof p.user === "string" ? p.user : "");
    deviceId = deviceId || (typeof p.device === "string" ? p.device : "") || (typeof p.name === "string" ? p.name : "");
}

const hasCoordinateNumbers = !isNaN(lat) && !isNaN(lon);
if (hasCoordinateNumbers && (lat < -90 || lat > 90 || lon < -180 || lon > 180)) {
    node.warn("Tracking-logik: lat/lon außerhalb des gültigen Bereichs");
    return null;
}
if (!hasCoordinateNumbers) {
    lat = null;
    lon = null;
}

if (!deviceId) deviceId = "unknown";
if (!username) username = "unknown";

const owntracksTid = isOwntracks && typeof p.tid === "string" && p.tid.trim()
    ? p.tid.trim().toLowerCase()
    : "";
let key = `${username}/${deviceId}`;
const position = {
    user: username,
    device: deviceId,
    key: key,
    owntracksTid: owntracksTid || null,
    lat: lat,
    lon: lon,
    accuracy: accuracy !== null && !isNaN(accuracy) ? accuracy : null,
    speed: speed !== null && !isNaN(speed) ? speed : null,
    heading: heading !== null && !isNaN(heading) ? heading : null,
    battery: battery !== null && !isNaN(battery) ? battery : null,
    timestamp: timestamp,
    receivedAt: receivedAt
};

let devices = global.get("devices") || {};
const previousDevicePosition = devices[key] && typeof devices[key] === "object" ? devices[key] : null;
const stabilizedPosition = stabilizePositionForStationaryDevice(position, previousDevicePosition);

let history = global.get("history") || [];
let historyByDevice = global.get("historyByDevice") || {};
let receivedCount = global.get("receivedCount") || 0;
let receivedCountByDevice = global.get("receivedCountByDevice") || {};
let trackingStateByDevice = global.get("trackingStateByDevice") || {};
let savedPlacesByDevice = global.get("savedPlacesByDevice") || {};
let savedRoutesByDevice = global.get("savedRoutesByDevice") || {};

if (owntracksTid) {
    const incomingKey = key;
    let matchedKey = "";
    Object.keys(devices).some(function (existingKey) {
        const existingDevice = devices[existingKey];
        if (!existingDevice || typeof existingDevice.owntracksTid !== "string") {
            return false;
        }
        if (String(existingDevice.owntracksTid).toLowerCase() === owntracksTid) {
            matchedKey = existingKey;
            return true;
        }
        return false;
    });

    if (matchedKey && matchedKey !== incomingKey) {
        const oldHistory = Array.isArray(historyByDevice[matchedKey]) ? historyByDevice[matchedKey] : [];
        const newHistory = Array.isArray(historyByDevice[incomingKey]) ? historyByDevice[incomingKey] : [];
        historyByDevice[incomingKey] = oldHistory.concat(newHistory);
        delete historyByDevice[matchedKey];

        const oldReceived = Number(receivedCountByDevice[matchedKey] || 0);
        const newReceived = Number(receivedCountByDevice[incomingKey] || 0);
        receivedCountByDevice[incomingKey] = oldReceived + newReceived;
        delete receivedCountByDevice[matchedKey];

        if (trackingStateByDevice[matchedKey]) {
            if (!trackingStateHasMissionAnchor(trackingStateByDevice[incomingKey])) {
                const mergedTracking = cloneTrackingStateForKeyMerge(trackingStateByDevice[matchedKey]);
                if (mergedTracking) {
                    trackingStateByDevice[incomingKey] = mergedTracking;
                }
            }
        }
        delete trackingStateByDevice[matchedKey];

        const oldPlaces = Array.isArray(savedPlacesByDevice[matchedKey]) ? savedPlacesByDevice[matchedKey] : [];
        const newPlaces = Array.isArray(savedPlacesByDevice[incomingKey]) ? savedPlacesByDevice[incomingKey] : [];
        savedPlacesByDevice[incomingKey] = oldPlaces.concat(newPlaces);
        delete savedPlacesByDevice[matchedKey];

        const oldRoutes = Array.isArray(savedRoutesByDevice[matchedKey]) ? savedRoutesByDevice[matchedKey] : [];
        const newRoutes = Array.isArray(savedRoutesByDevice[incomingKey]) ? savedRoutesByDevice[incomingKey] : [];
        savedRoutesByDevice[incomingKey] = oldRoutes.concat(newRoutes);
        delete savedRoutesByDevice[matchedKey];

        if (devices[matchedKey] && !devices[incomingKey]) {
            devices[incomingKey] = devices[matchedKey];
        }
        delete devices[matchedKey];
    }

    key = incomingKey;
    stabilizedPosition.key = key;
    stabilizedPosition.owntracksTid = owntracksTid;
}

let lastGoodByDevice = global.get("lastGoodPositionByDevice") || {};
const prevDeviceEntry = devices[key];
const gpsFixOk = coordinatesLookValidForBoat(stabilizedPosition);
if (gpsFixOk) {
    lastGoodByDevice[key] = snapshotLastGoodForDevice(stabilizedPosition, key);
}
global.set("lastGoodPositionByDevice", lastGoodByDevice);

let positionForDeviceMap = stabilizedPosition;
let positionForLastGlobal = stabilizedPosition;
if (!gpsFixOk) {
    if (coordinatesLookValidForBoat(prevDeviceEntry)) {
        positionForDeviceMap = prevDeviceEntry;
        positionForLastGlobal = prevDeviceEntry;
    } else if (lastGoodByDevice[key] && coordinatesLookValidForBoat(lastGoodByDevice[key])) {
        const frozen = lastGoodByDevice[key];
        positionForDeviceMap = Object.assign({}, frozen, { key: key });
        positionForLastGlobal = positionForDeviceMap;
    }
}

global.set("lastPosition", positionForLastGlobal);
if (!global.get("historyCleaned")) {
    history = simplifyPath(history, SIMPLIFY_TOLERANCE_M);
    if (history.length > MAX_HISTORY) history = history.slice(-MAX_HISTORY);
    Object.keys(historyByDevice).forEach(function (deviceKey) {
        let deviceHistory = historyByDevice[deviceKey] || [];
        deviceHistory = simplifyPath(deviceHistory, SIMPLIFY_TOLERANCE_M);
        if (deviceHistory.length > MAX_HISTORY) deviceHistory = deviceHistory.slice(-MAX_HISTORY);
        historyByDevice[deviceKey] = deviceHistory;
    });
    global.set("historyCleaned", true);
}

if (gpsFixOk && stabilizedPosition.lat !== null && stabilizedPosition.lon !== null) {
    receivedCount += 1;
    receivedCountByDevice[key] = (receivedCountByDevice[key] || 0) + 1;
}

const deviceTrackingState = trackingStateByDevice[key] || {};
const trackingIsActiveForDevice = !!deviceTrackingState.active;

if (trackingIsActiveForDevice && gpsFixOk && stabilizedPosition.lat !== null && stabilizedPosition.lon !== null) {
    let deviceHistory = historyByDevice[key] || [];
    const deviceAppendResult = appendToHistory(deviceHistory, stabilizedPosition);
    historyByDevice[key] = deviceAppendResult.history;
}

global.set("history", history);
global.set("historyByDevice", historyByDevice);
global.set("receivedCount", receivedCount);
global.set("receivedCountByDevice", receivedCountByDevice);
global.set("trackingStateByDevice", trackingStateByDevice);
global.set("savedPlacesByDevice", savedPlacesByDevice);
global.set("savedRoutesByDevice", savedRoutesByDevice);

devices[key] = positionForDeviceMap;
global.set("devices", devices);

msg.payload = stabilizedPosition;
return msg;

let lastPosition = global.get("lastPosition") || null;

msg.payload = {
    ok: true,
    data: lastPosition
};

return msg;

const lastPosition = global.get("lastPosition") || null;
const devices = global.get("devices") || {};
const targets = [];

function parseTarget(source) {
    if (!source || typeof source !== "object") {
        return null;
    }
    const user = typeof source.user === "string" ? source.user.trim() : "";
    const device = typeof source.device === "string" ? source.device.trim() : "";
    if (!user || !device) {
        return null;
    }
    return { user: user, device: device };
}

function parseDeviceKey(source) {
    if (!source || typeof source !== "object") {
        return null;
    }
    const rawKey = typeof source.deviceKey === "string" ? source.deviceKey.trim() : "";
    if (!rawKey || rawKey.indexOf("/") <= 0) {
        return null;
    }
    const slashIndex = rawKey.indexOf("/");
    const user = rawKey.slice(0, slashIndex).trim();
    const device = rawKey.slice(slashIndex + 1).trim();
    if (!user || !device) {
        return null;
    }
    return { user: user, device: device };
}

function parseOwntracksTid(source) {
    if (!source || typeof source !== "object") {
        return "";
    }
    const rawTid = typeof source.owntracksTid === "string" ? source.owntracksTid.trim().toLowerCase() : "";
    return rawTid;
}

function resolveTargetByOwntracksTid(rawTid) {
    if (!rawTid) {
        return null;
    }
    let matchedKey = "";
    Object.keys(devices).some(function (deviceKey) {
        const entry = devices[deviceKey];
        if (!entry || typeof entry !== "object") {
            return false;
        }
        const entryTid = typeof entry.owntracksTid === "string" ? entry.owntracksTid.trim().toLowerCase() : "";
        if (entryTid && entryTid === rawTid) {
            matchedKey = deviceKey;
            return true;
        }
        return false;
    });
    if (!matchedKey || matchedKey.indexOf("/") <= 0) {
        return null;
    }
    const slashIndex = matchedKey.indexOf("/");
    const user = matchedKey.slice(0, slashIndex).trim();
    const device = matchedKey.slice(slashIndex + 1).trim();
    if (!user || !device) {
        return null;
    }
    return { user: user, device: device };
}

let explicitTarget = null;
let explicitSource = null;

try {
    const reqBody = msg.req && msg.req.body ? msg.req.body : null;
    const reqTid = parseOwntracksTid(reqBody);
    explicitTarget = resolveTargetByOwntracksTid(reqTid) || parseTarget(reqBody) || parseDeviceKey(reqBody);
    if (explicitTarget) {
        explicitSource = reqTid ? "req.body.tid" : "req.body";
    }
} catch (err) {
    explicitTarget = null;
}
if (!explicitTarget) {
    const payloadTid = parseOwntracksTid(msg.payload);
    explicitTarget = resolveTargetByOwntracksTid(payloadTid) || parseTarget(msg.payload) || parseDeviceKey(msg.payload);
    if (explicitTarget) {
        explicitSource = payloadTid ? "payload.tid" : "payload";
    }
}

if (explicitTarget) {
    targets.push(explicitTarget);
} else if (lastPosition && typeof lastPosition.user === "string" && typeof lastPosition.device === "string" && lastPosition.user && lastPosition.device) {
    targets.push({ user: lastPosition.user, device: lastPosition.device });
} else {
    Object.keys(devices).forEach(function (deviceKey) {
        const slashIndex = deviceKey.indexOf("/");
        if (slashIndex > 0) {
            targets.push({
                user: deviceKey.slice(0, slashIndex),
                device: deviceKey.slice(slashIndex + 1)
            });
        }
    });
}

if (targets.length === 0) {
    msg.statusCode = 400;
    msg.payload = { ok: false, message: "Kein OwnTracks-Gerät bekannt. Zuerst eine Position empfangen." };
    return [null, msg];
}

const mqttMessages = targets.map(function (targetEntry) {
    const commandTopic = "owntracks/" + targetEntry.user + "/" + targetEntry.device + "/cmd";
    return {
        topic: commandTopic,
        payload: JSON.stringify({ _type: "cmd", action: "reportLocation" })
    };
});

msg.statusCode = 200;
msg.payload = {
    ok: true,
    count: targets.length,
    targets: targets,
    mode: explicitTarget ? "single" : "fallback",
    source: explicitSource || "auto"
};
return [mqttMessages, msg];

let history = global.get("history") || [];
let receivedCount = global.get("receivedCount");
if (typeof receivedCount !== "number" || receivedCount < history.length) {
    receivedCount = history.length;
}

msg.payload = {
    ok: true,
    count: history.length,
    received: receivedCount,
    data: history
};

return msg;

function coordinatesLookValidForBoatApi(p) {
    if (!p || typeof p !== "object") return false;
    if (typeof p.lat !== "number" || typeof p.lon !== "number") return false;
    if (!Number.isFinite(p.lat) || !Number.isFinite(p.lon)) return false;
    if (Math.abs(p.lat) < 1e-7 && Math.abs(p.lon) < 1e-7) return false;
    if (Math.abs(p.lat) > 90 || Math.abs(p.lon) > 180) return false;
    return true;
}

let devices = global.get("devices") || {};
let lastGood = global.get("lastGoodPositionByDevice") || {};
const merged = {};
Object.keys(devices).forEach(function (k) {
    merged[k] = devices[k];
});
Object.keys(lastGood).forEach(function (k) {
    const live = merged[k];
    if (!coordinatesLookValidForBoatApi(live) && coordinatesLookValidForBoatApi(lastGood[k])) {
        merged[k] = Object.assign({}, lastGood[k], { key: k });
    }
});

msg.payload = {
    ok: true,
    count: Object.keys(merged).length,
    data: merged
};

return msg;

const req = msg.req || {};
const params = req.params || {};
const user = typeof params.user === "string" ? params.user.trim() : "";
const device = typeof params.device === "string" ? params.device.trim() : "";
if (!user || !device) {
    msg.statusCode = 400;
    msg.payload = { ok: false, message: "user und device sind erforderlich" };
    return msg;
}
const key = user + "/" + device;

const devices = global.get("devices") || {};
if (devices[key]) {
    delete devices[key];
    global.set("devices", devices);
}

const historyByDevice = global.get("historyByDevice") || {};
delete historyByDevice[key];
